-- Step 1: Upsert into raw_athletes (idempotent)

-- Step 2: Promote clean records from staging → athletes table
-- (Only records where review_flag = false and required fields are non-null)
   height_cm, weight_kg,
   location_city, location_state, location_country,
   source, source_url, verified)
SELECT
  name,
  discipline:discipline_type,
  skating_level:skating_level,
  partner_role:partner_role,
  height_cm,
  weight_kg,
  location_city,
  location_state,
  location_country,
  source,
  source_url,
  false
FROM raw_athletes
WHERE review_flag = false
  AND name IS NOT NULL
  AND discipline IS NOT NULL
  AND skating_level IS NOT NULL
  AND height_cm IS NOT NULL
ON CONFLICT (source_url) DO NOTHING;

-- Mark promoted records in staging
UPDATE raw_athletes SET promoted = true
WHERE review_flag = false
  AND name IS NOT NULL
  AND discipline IS NOT NULL
  AND skating_level IS NOT NULL
  AND height_cm IS NOT NULL;

